    private Instructor SeedInstructor(string first = "John", string last = "Doe")
    {
        var instructor = new Instructor
        {
            FirstMidName = first,
            LastName = last,
            HireDate = new DateTime(2010, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private (Instructor instructor, Course course) SeedInstructorWithCourse()
    {
        var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 1001, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var instructor = new Instructor
        {
            FirstMidName = "John",
            LastName = "Doe",
            HireDate = new DateTime(2010, 1, 1),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = course.CourseID }
            }
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        return (instructor, course);
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithInstructorIndexData()
    {
        SeedInstructor();

        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Single(model.Instructors);
    }

    [Fact]
    public void Index_MultipleInstructors_ReturnsAllOrderedByLastName()
    {
        SeedInstructor("Alice", "Zebra");
        SeedInstructor("Bob", "Alpha");

        var result = _controller.Index(null, null) as ViewResult;
        var model = Assert.IsType<InstructorIndexData>(result.Model);

        Assert.Equal(2, model.Instructors.Count());
        Assert.Equal("Alpha", model.Instructors.First().LastName);
    }

    [Fact]
    public void Index_WithSelectedInstructor_ShowsCourses()
    {
        var (instructor, course) = SeedInstructorWithCourse();

        var result = _controller.Index(instructor.ID, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Single(model.Courses);
        Assert.Equal(course.CourseID, model.Courses.First().CourseID);
    }

    [Fact]
    public void Index_NoInstructorSelected_CoursesIsNull()
    {
        SeedInstructor();

        var result = _controller.Index(null, null) as ViewResult;
        var model = Assert.IsType<InstructorIndexData>(result.Model);

        Assert.Null(model.Courses);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
