namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly CoursesController _controller;
    private readonly SchoolContext _context;
    private readonly string _tempDir;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();

        var mockEnv = new Mock<IWebHostEnvironment>();
        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempDir);
        mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        var mockLogger = new Mock<ILogger<CoursesController>>();

        _controller = new CoursesController(_context, mockEnv.Object, mockLogger.Object);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());

        SeedDepartment();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
            try { Directory.Delete(_tempDir, true); } catch { }
    }

    private Department SeedDepartment()
    {
        var dept = _context.Departments.FirstOrDefault();
        if (dept != null) return dept;

        dept = new Department
