{"file_text": "using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        _sut = new NotificationService();
        // Drain any pre-existing messages from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _sut.Dispose();
    }

    [Fact]
    public void SendNotification_EnqueuesMessage()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("TestUser", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
    {
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains("Chemistry", notification.Message);
        Assert.Contains("created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Student", "42", EntityOperation.DELETE);

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains("42", notification.Message);
        Assert.Contains("deleted", notification.Message);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_OperationTypes_GenerateCorrectMessages(EntityOperation operation, string expectedVerb)
    {
        _sut.SendNotification("Test", "1", "TestEntity", operation);

        var notification = _sut.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains(expectedVerb, notification.Message);
    }

    [Fact]
    public void SendNotification_DefaultUser_IsSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_ReturnsInFifoOrder()
    {
        _sut.SendNotification("First", "1", EntityOperation.CREATE);
        _sut.SendNotification("Second", "2", EntityOperation.UPDATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        Assert.Equal("First", first.EntityType);
        Assert.Equal("Second", second.EntityType);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        var exception = Record.Exception(() => _sut.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _sut.ReceiveNotification();

        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_CreateMessage_ContainsNew()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.StartsWith("New ", notification.Message);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }
}
