{"file_text": "using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly StudentsController _controller;
    private readonly SchoolContext _context;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new StudentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Student SeedStudent(string first = "John", string last = "Doe", DateTime? enrollDate = null)
    {
        var student = new Student
        {
            FirstMidName = first,
            LastName = last,
            EnrollmentDate = enrollDate ?? new DateTime(2020, 9, 1)
        };
        _context.Students.Add(student);
        _context.SaveChanges();
        return student;
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithPaginatedStudents()
    {
        SeedStudent("Alice", "Smith");
        SeedStudent("Bob", "Jones");

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        SeedStudent("Alice", "Zebra");
        SeedStudent("Bob", "Alpha");

        var result = _controller.Index(null, null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);

        Assert.Equal("Alpha", model[0].LastName);
        Assert.Equal("Zebra", model[1].LastName);
    }

    [Fact]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        SeedStudent("Alice", "Alpha");
        SeedStudent("Bob", "Zebra");

        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);

        Assert.Equal("Zebra", model[0].LastName);
        Assert.Equal("Alpha", model[1].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        SeedStudent("Alice", "A", new DateTime(2021, 1, 1));
        SeedStudent("Bob", "B", new DateTime(2019, 1, 1));

        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);

        Assert.Equal("B", model[0].LastName); // earlier date first
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        SeedStudent("Alice", "A", new DateTime(2019, 1, 1));
        SeedStudent("Bob", "B", new DateTime(2021, 1, 1));

        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);

        Assert.Equal("B", model[0].LastName); // later date first
    }

    [Fact]
    public void Index_SearchString_FiltersStudentsByLastName()
    {
        SeedStudent("Alice", "Smith");
        SeedStudent("Bob", "Jones");

        var result = _controller.Index(null, null, "Smith", null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);

        Assert.Single(model);
        Assert.Equal("Smith", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_FiltersStudentsByFirstName()
    {
        SeedStudent("Alice", "Smith");
        SeedStudent("Bob", "Jones");

        var result = _controller.Index(null, null, "Alice", null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);

        Assert.Single(model);
        Assert.Equal("Alice", model[0].FirstMidName);
    }

    [Fact]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        for (int i = 0; i < 15; i++) SeedStudent($"Student{i}", $"Last{i}");

        // Passing a non-null searchString resets page to 1
        var result = _controller.Index(null, null, "Last1", null) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Index_NullSearch_UsesCurrentFilter()
    {
        SeedStudent("Alice", "Smith");
        SeedStudent("Bob", "Jones");

        var result = _controller.Index(null, "Smith", null, null) as ViewResult;
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);

        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagSortParameters()
    {
        _controller.Index(null, null, null, null);

        Assert.Equal("name_desc", (string)_controller.ViewBag.NameSortParm);
        Assert.Equal("Date", (string)_controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_NameDescSort_TogglesNameSortParm()
    {
        _controller.Index("name_desc", null, null, null);

        Assert.Equal("", (string)_controller.ViewBag.NameSortParm);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsStudentView()
    {
        var student = SeedStudent();

        var result = _controller.Details(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(_context.Students);
    }

    [Fact]
    public void Create_Post_DefaultEnrollmentDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_Post_DateBelow1753_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(1000, 1, 1)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.Equal(student, result.Model);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsStudentView()
    {
        var student = SeedStudent();

