using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Data;

public class DbInitializerTests
{
    [Fact]
    public void Initialize_SeedsEmptyDatabase()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.NotEmpty(context.Students);
        Assert.NotEmpty(context.Instructors);
        Assert.NotEmpty(context.Departments);
        Assert.NotEmpty(context.Courses);
        Assert.NotEmpty(context.Enrollments);
        Assert.NotEmpty(context.CourseAssignments);
        Assert.NotEmpty(context.OfficeAssignments);
    }

    [Fact]
    public void Initialize_SeedsCorrectNumberOfStudents()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.Equal(8, context.Students.Count());
    }

    [Fact]
    public void Initialize_SeedsCorrectNumberOfInstructors()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.Equal(5, context.Instructors.Count());
    }

    [Fact]
    public void Initialize_SeedsCorrectNumberOfDepartments()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.Equal(4, context.Departments.Count());
    }

    [Fact]
    public void Initialize_SeedsCorrectNumberOfCourses()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.Equal(7, context.Courses.Count());
    }

    [Fact]
    public void Initialize_SkipsWhenDataExists()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        context.Students.Add(new Student
        {
            FirstMidName = "Existing",
            LastName = "Student",
            EnrollmentDate = DateTime.Today
        });
        context.SaveChanges();

        DbInitializer.Initialize(context);

        // Should only have the one pre-seeded student
        Assert.Single(context.Students);
    }

    [Fact]
    public void Initialize_CalledTwice_IsIdempotent()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);
        var studentCount = context.Students.Count();

        DbInitializer.Initialize(context);

        Assert.Equal(studentCount, context.Students.Count());
    }

    [Fact]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.Contains(context.Enrollments, e => e.Grade == Grade.A);
        Assert.Contains(context.Enrollments, e => e.Grade == Grade.B);
        Assert.Contains(context.Enrollments, e => e.Grade == Grade.C);
        Assert.Contains(context.Enrollments, e => e.Grade == null);
    }

    [Fact]
    public void Initialize_SeedsOfficeAssignments()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.Equal(3, context.OfficeAssignments.Count());
    }
}
