using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models;

public class PersonTests
{
    [Fact]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = DateTime.Today
        };

        Assert.Equal("Smith, John", student.FullName);
    }

    [Fact]
    public void FullName_Instructor_ReturnsCorrectFormat()
    {
        var instructor = new Instructor
        {
            LastName = "Doe",
            FirstMidName = "Jane",
            HireDate = DateTime.Today
        };

        Assert.Equal("Doe, Jane", instructor.FullName);
    }

    [Fact]
    public void Student_EnrollmentDate_CanBeSet()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student { LastName = "A", FirstMidName = "B", EnrollmentDate = date };

        Assert.Equal(date, student.EnrollmentDate);
    }

    [Fact]
    public void Instructor_HireDate_CanBeSet()
