using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class HomeControllerTests : IDisposable
{
    private readonly HomeController _controller;
    private readonly Data.SchoolContext _context;

    public HomeControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new HomeController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void About_ReturnsViewWithEnrollmentGroups()
    {
        _context.Students.Add(new Student { LastName = "A", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) });
        _context.Students.Add(new Student { LastName = "C", FirstMidName = "D", EnrollmentDate = new DateTime(2020, 9, 1) });
        _context.Students.Add(new Student { LastName = "E", FirstMidName = "F", EnrollmentDate = new DateTime(2021, 9, 1) });
        _context.SaveChanges();

        var result = _controller.About() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<EnrollmentDateGroup>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void About_EmptyDatabase_ReturnsEmptyList()
    {
        var result = _controller.About() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<EnrollmentDateGroup>>(result.Model);
        Assert.Empty(model);
    }

    [Fact]
    public void About_GroupsStudentsByEnrollmentDate()
    {
        _context.Students.Add(new Student { LastName = "A", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) });
        _context.Students.Add(new Student { LastName = "C", FirstMidName = "D", EnrollmentDate = new DateTime(2020, 9, 1) });
        _context.SaveChanges();

        var result = _controller.About() as ViewResult;
        var model = Assert.IsType<List<EnrollmentDateGroup>>(result.Model);

        Assert.Single(model);
        Assert.Equal(2, model[0].StudentCount);
    }

    [Fact]
    public void Contact_ReturnsViewWithMessage()
    {
        var result = _controller.Contact() as ViewResult;

        Assert.NotNull(result);
        Assert.Equal("Your contact page.", _controller.ViewBag.Message);
    }

    [Fact]
    public void Error_ReturnsViewResult()
    {
        var result = _controller.Error();
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Unauthorized_ReturnsViewWithPermissionMessage()
    {
        var result = _controller.Unauthorized() as ViewResult;

        Assert.NotNull(result);
        Assert.Contains("permission", (string)_controller.ViewBag.Message);
    }
}

