using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly CoursesController _controller;
    private readonly SchoolContext _context;
    private readonly string _tempDir;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();

        var mockEnv = new Mock<IWebHostEnvironment>();
        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempDir);
        mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        var mockLogger = new Mock<ILogger<CoursesController>>();

        _controller = new CoursesController(_context, mockEnv.Object, mockLogger.Object);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());

        SeedDepartment();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
            try { Directory.Delete(_tempDir, true); } catch { }
    }

    private Department SeedDepartment()
    {
        var dept = _context.Departments.FirstOrDefault();
        if (dept != null) return dept;

        dept = new Department
        {
            Name = "Test Dept",
            Budget = 100000,
            StartDate = new DateTime(2020, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private Course SeedCourse(int courseId = 1001, string title = "Test Course")
    {
        var dept = SeedDepartment();
        var course = new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        SeedCourse();

        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<Course>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<Course>>(result.Model);
        Assert.Empty(model);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsCourseView()
    {
        var course = SeedCourse();

        var result = _controller.Details(course.CourseID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(course.CourseID, model.CourseID);
    }

