using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly DepartmentsController _controller;
    private readonly SchoolContext _context;

    public DepartmentsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new DepartmentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Instructor SeedInstructor(string first = "John", string last = "Doe")
    {
        var instructor = new Instructor
        {
            FirstMidName = first,
            LastName = last,
            HireDate = new DateTime(2010, 1, 1)
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private Department SeedDepartment(string name = "Test Dept")
    {
        var dept = new Department
        {
            Name = name,
            Budget = 100000,
            StartDate = new DateTime(2020, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        SeedDepartment();

        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<Department>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<Department>>(result.Model);
        Assert.Empty(model);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsDepartmentView()
    {
        var dept = SeedDepartment();

        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void Details_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorsDropdown()
    {
        SeedInstructor();

        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = new Department
        {
            Name = "New Dept",
            Budget = 200000,
            StartDate = new DateTime(2023, 1, 1)
        };

        var result = _controller.Create(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(_context.Departments);
    }

    [Fact]
    public void Create_Post_WithInstructor_SavesDepartment()
    {
        var instructor = SeedInstructor();
        var dept = new Department
        {
            Name = "New Dept",
            Budget = 200000,
            StartDate = new DateTime(2023, 1, 1),
            InstructorID = instructor.ID
        };

        var result = _controller.Create(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        var saved = _context.Departments.Find(dept.DepartmentID);
        Assert.Equal(instructor.ID, saved.InstructorID);
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        SeedInstructor();
        var dept = new Department();

        var result = _controller.Create(dept) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsDepartmentView()
    {
        var dept = SeedDepartment();
        SeedInstructor();

        var result = _controller.Edit((int?)dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void Edit_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Edit((int?)999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = SeedDepartment();
        SeedInstructor();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        dept.Name = "Updated";

        var result = _controller.Edit(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        SeedInstructor();
        var dept = SeedDepartment();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = _controller.Edit(dept) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsDepartmentView()
    {
        var dept = SeedDepartment();

        var result = _controller.Delete(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void Delete_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var dept = SeedDepartment();

        var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Departments.Find(dept.DepartmentID));
    }
}

