using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly InstructorsController _controller;
    private readonly SchoolContext _context;

    public InstructorsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Instructor SeedInstructor(string first = "John", string last = "Doe")
    {
        var instructor = new Instructor
        {
            FirstMidName = first,
            LastName = last,
            HireDate = new DateTime(2010, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private (Instructor instructor, Course course) SeedInstructorWithCourse()
    {
        var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 1001, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var instructor = new Instructor
        {
            FirstMidName = "John",
            LastName = "Doe",
            HireDate = new DateTime(2010, 1, 1),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = course.CourseID }
            }
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        return (instructor, course);
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithInstructorIndexData()
    {
        SeedInstructor();

        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Single(model.Instructors);
    }

    [Fact]
    public void Index_MultipleInstructors_ReturnsAllOrderedByLastName()
    {
        SeedInstructor("Alice", "Zebra");
        SeedInstructor("Bob", "Alpha");

        var result = _controller.Index(null, null) as ViewResult;
        var model = Assert.IsType<InstructorIndexData>(result.Model);

        Assert.Equal(2, model.Instructors.Count());
        Assert.Equal("Alpha", model.Instructors.First().LastName);
    }

    [Fact]
    public void Index_WithSelectedInstructor_ShowsCourses()
    {
        var (instructor, course) = SeedInstructorWithCourse();

        var result = _controller.Index(instructor.ID, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Single(model.Courses);
        Assert.Equal(course.CourseID, model.Courses.First().CourseID);
    }

    [Fact]
    public void Index_NoInstructorSelected_CoursesIsNull()
    {
        SeedInstructor();

        var result = _controller.Index(null, null) as ViewResult;
        var model = Assert.IsType<InstructorIndexData>(result.Model);

        Assert.Null(model.Courses);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsInstructorView()
    {
        var instructor = SeedInstructor();

        var result = _controller.Details(instructor.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(instructor.ID, model.ID);
    }

    [Fact]
    public void Details_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsViewWithEmptyCourseAssignments()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.Empty(model.CourseAssignments);
    }

    [Fact]
    public void Create_Get_PopulatesAssignedCourseData()
    {
        var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        _context.Courses.Add(new Course { CourseID = 5001, Title = "Course A", Credits = 3, DepartmentID = dept.DepartmentID });
        _context.SaveChanges();

        var result = _controller.Create() as ViewResult;

        Assert.NotNull(_controller.ViewBag.Courses);
        var courses = Assert.IsType<List<AssignedCourseData>>((List<AssignedCourseData>)_controller.ViewBag.Courses);
        Assert.Single(courses);
        Assert.False(courses[0].Assigned);
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Instructor",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        _context.Courses.Add(new Course { CourseID = 2001, Title = "Course", Credits = 3, DepartmentID = dept.DepartmentID });
        _context.SaveChanges();

        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Instructor",
            HireDate = new DateTime(2023, 1, 1)
        };
        var selectedCourses = new[] { "2001" };

        var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Single(instructor.CourseAssignments);
        Assert.Equal(2001, instructor.CourseAssignments.First().CourseID);
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsInstructorView()
    {
        var instructor = SeedInstructor();

        var result = _controller.Delete(instructor.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal(instructor.ID, model.ID);
    }

    [Fact]
    public void Delete_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        var instructor = SeedInstructor();

        var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Instructors.Find(instructor.ID));
    }

    [Fact]
    public void DeleteConfirmed_NullsDepartmentAdministrator()
    {
        var instructor = SeedInstructor();
        var dept = new Department
        {
            Name = "Test",
            Budget = 100000,
            StartDate = DateTime.Today,
            InstructorID = instructor.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _controller.DeleteConfirmed(instructor.ID);

        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.Null(updatedDept.InstructorID);
    }

    [Fact]
    public void DeleteConfirmed_RemovesOfficeAssignment()
    {
        var instructor = SeedInstructor();
        _context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Room 101"
        });
        _context.SaveChanges();

        _controller.DeleteConfirmed(instructor.ID);

        Assert.Null(_context.Instructors.Find(instructor.ID));
    }
}

